Wlan to Ethernet-Bridge Hier ein Script welches, benötigte Programme herunterlädt, sowie ein systemd-unit baut, mit welchem sich die Bridge start lässt.
#!/usr/bin/env bash set -e [ $EUID -ne 0 ] &amp;&amp; echo &#34;run as root&#34; &gt;&amp;2 &amp;&amp; exit 1 ########################################################## # You should not need to update anything below this line # ########################################################## # Because of the following two programs wifi and ethernet will share the same subnet # # parprouted - Proxy ARP IP bridging daemon # dhcp-helper - DHCP/BOOTP relay agent apt update &amp;&amp; apt install -y parprouted dhcp-helper systemctl stop dhcp-helper systemctl enable dhcp-helper # Enable ipv4 forwarding. sed -i&#39;&#39; s/#net.ipv4.ip_forward=1/net.ipv4.ip_forward=1/ /etc/sysctl.conf # Service configuration for standard WiFi connection. Connectivity will # be lost if the username and password are incorrect. systemctl restart wpa_supplicant.service # Enable IP forwarding for wlan0 if it&#39;s not already enabled. grep &#39;^option ip-forwarding 1$&#39; /etc/dhcpcd.conf || printf &#34;option ip-forwarding 1
&#34; &gt;&gt; /etc/dhcpcd.conf # Disable dhcpcd control of eth0. grep &#39;^denyinterfaces eth0$&#39; /etc/dhcpcd.conf || printf &#34;denyinterfaces eth0
&#34; &gt;&gt; /etc/dhcpcd.conf # Configure dhcp-helper. cat &gt; /etc/default/dhcp-helper &lt;&lt;EOF DHCPHELPER_OPTS=&#34;-b wlan0&#34; EOF # Enable avahi reflector if it&#39;s not already enabled. sed -i&#39;&#39; &#39;s/#enable-reflector=no/enable-reflector=yes/&#39; /etc/avahi/avahi-daemon.conf grep &#39;^enable-reflector=yes$&#39; /etc/avahi/avahi-daemon.conf || { printf &#34;something went wrong...

&#34; printf &#34;Manually set &#39;enable-reflector=yes in /etc/avahi/avahi-daemon.conf&#39;
&#34; } # I have to admit, I do not understand ARP and IP forwarding enough to explain # exactly what is happening here. I am building off the work of others. In short # this is a service to forward traffic from WiFi to Ethernet. cat &lt;&lt;&#39;EOF&#39; &gt;/usr/lib/systemd/system/parprouted.service [Unit] Description=proxy arp routing service Documentation=https://raspberrypi.stackexchange.com/q/88954/79866 Requires=sys-subsystem-net-devices-wlan0.device dhcpcd.service After=sys-subsystem-net-devices-wlan0.device dhcpcd.service [Service] Type=forking # Restart until wlan0 gained carrier Restart=on-failure RestartSec=5 TimeoutStartSec=30 # clone the dhcp-allocated IP to eth0 so dhcp-helper will relay for the correct subnet ExecStartPre=/bin/bash -c &#39;/sbin/ip addr add $(/sbin/ip -4 -br addr show wlan0 | /bin/grep -Po &#34;\d+\.\d+\.\d+\.\d+&#34;)/32 dev eth0&#39; ExecStartPre=/sbin/ip link set dev eth0 up ExecStartPre=/sbin/ip link set wlan0 promisc on ExecStart=-/usr/sbin/parprouted eth0 wlan0 ExecStopPost=/sbin/ip link set wlan0 promisc off ExecStopPost=/sbin/ip link set dev eth0 down ExecStopPost=/bin/bash -c &#39;/sbin/ip addr del $(/sbin/ip -4 -br addr show wlan0 | /bin/grep -Po &#34;\d+\.\d+\.\d+\.\d+&#34;)/32 dev eth0&#39; [Install] WantedBy=wpa_supplicant.service EOF systemctl daemon-reload systemctl enable parprouted systemctl start parprouted dhcp-helper Normalerweise sollte das Script auch unter ~/.scripts/raspberrypi/bridge.sh liegen.
